func solve(nums []int64) int64 {
	type pair struct {
		a, b int64
	}
	var pairs []pair
	for i := 0; i < len(nums); i++ {
		for j := i + 1; j < len(nums); j++ {
			pairs = append(pairs, pair{nums[i], nums[j]})
		}
	}

	sort.Slice(pairs, func(i, j int) bool {
		return pairs[i].a < pairs[j].a || (pairs[i].a == pairs[j].a && pairs[i].b < pairs[j].b)
	})

	count := int64(0)
	for i := 0; i < len(pairs); i++ {
		a, b := pairs[i].a, pairs[i].b
		minVal := int64(0)
		maxVal := int64(0)
		if a < b {
			minVal = b - a
			maxVal = a + b
		} else {
			minVal = a - b
			maxVal = a + b
		}
		minAbs := int64(0)
		if abs(a) < abs(b) {
			minAbs = abs(a)
		} else {
			minAbs = abs(b)
		}
		maxAbs := int64(0)
		if abs(a) > abs(b) {
			maxAbs = abs(a)
		} else {
			maxAbs = abs(b)
		}
		if minVal <= minAbs && maxVal >= maxAbs {
			count++
		}
	}
	return count
